  1	import * as React from 'react';
  2	import {
  3	  calculateRadius,
  4	  createWizardNodeState,
  5	} from '@odf/core/components/utils';
  6	import { useNodesData } from '@odf/core/hooks';
  7	import { DiscoveredDisk, DiskMetadata, NodeData } from '@odf/core/types';
  8	import { StatusBox } from '@odf/shared/generic/status-box';
  9	import { getName } from '@odf/shared/selectors';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { humanizeBinaryBytes } from '@odf/shared/utils';
 12	import * as _ from 'lodash-es';
 13	import { ChartDonut, ChartLabel } from '@patternfly/react-charts';
 14	import { Button } from '@patternfly/react-core';
 15	import { WizardState, WizardDispatch } from '../../reducer';
 16	import { SelectedNodesTable } from '../capacity-and-nodes-step/selected-nodes-table';
 17	import { Modal, DiskListModal } from './disk-list-modal';
 18	import './selected-capacity.scss';
 19	
 20	const getTotalCapacity = (disks: DiscoveredDisk[]): number =>
 21	  disks.reduce((total: number, disk: DiskMetadata) => total + disk.size, 0);
 22	
 23	export const SelectedCapacity: React.FC<SelectedCapacityProps> = ({
 24	  state,
 25	  chartDisks,
 26	  allDiscoveredDisks,
 27	  dispatch,
 28	}) => {
 29	  const { t } = useCustomTranslation();
 30	  const [showNodeList, setShowNodeList] = React.useState(false);
 31	  const [showDiskList, setShowDiskList] = React.useState(false);
 32	
 33	  React.useEffect(() => {
 34	    const chartNodes: Set<string> = chartDisks.reduce(
 35	      (data: Set<string>, disk: DiscoveredDisk) => data.add(disk.node),
 36	      new Set()
 37	    );
 38	    if (!_.isEqual(chartNodes, state.chartNodes)) {
 39	      dispatch({
 40	        type: 'wizard/setCreateLocalVolumeSet',
 41	        payload: { field: 'chartNodes', value: chartNodes },
 42	      });
 43	    }
 44	  }, [chartDisks, dispatch, state.chartNodes]);
 45	
 46	  const totalCapacity = getTotalCapacity(allDiscoveredDisks);
 47	  const selectedCapacity = getTotalCapacity(chartDisks);
 48	
 49	  const donutData = [
 50	    { x: 'Selected', y: selectedCapacity },
 51	    {
 52	      x: 'Available',
 53	      y: Number(totalCapacity) - Number(selectedCapacity),
 54	    },
 55	  ];
 56	  const { podStatusOuterRadius: radius } = calculateRadius(220);
 57	
 58	  return (
 59	    <div className="odf-install__chart-wrapper">
 60	      <div className="odf-install_capacity-header">
 61	        {t('Selected capacity')}
 62	      </div>
 63	      <div className="odf-install__stats">
 64	        <Button
 65	          variant="link"
 66	          isDisabled={!state.chartNodes.size}
 67	          onClick={() => setShowNodeList(true)}
 68	          className="odf-install__node-list-btn"
 69	        >
 70	          {t('{{nodes, number}} Node', {
 71	            nodes: state.chartNodes.size,
 72	            count: state.chartNodes.size,
 73	          })}
 74	        </Button>
 75	        <div className="odf-install_stats--divider" />
 76	        <Button
 77	          variant="link"
 78	          isDisabled={!chartDisks.length}
 79	          onClick={() => setShowDiskList(true)}
 80	          className="odf-install__disk-list-btn"
 81	        >
 82	          {t('{{disks, number}} Disk', {
 83	            disks: chartDisks.length,
 84	            count: chartDisks.length,
 85	          })}
 86	        </Button>
 87	      </div>
 88	      <ChartDonut
 89	        ariaDesc={t('Selected versus Available Capacity')}
 90	        ariaTitle={t('Selected versus Available Capacity')}
 91	        height={220}
 92	        width={220}
 93	        radius={radius}
 94	        data={donutData}
 95	        labels={({ datum }) =>
 96	          `${humanizeBinaryBytes(datum.y).string} ${datum.x}`
 97	        }
 98	        subTitle={t('Out of {{capacity}}', {
 99	          capacity: humanizeBinaryBytes(totalCapacity).string,
100	        })}
101	        title={humanizeBinaryBytes(selectedCapacity).string}
102	        constrainToVisibleArea
103	        subTitleComponent={
104	          <ChartLabel
105	            dy={5}
106	            style={{ fill: `var(--pf-t--color--gray--40)` }}
107	          />
108	        }
109	      />
110	      <DiskListModal
111	        showDiskList={showDiskList}
112	        disks={chartDisks}
113	        onCancel={() => setShowDiskList(false)}
114	      />
115	      <NodeListModal
116	        showNodeList={showNodeList}
117	        filteredNodes={state.chartNodes}
118	        onCancel={() => setShowNodeList(false)}
119	      />
120	    </div>
121	  );
122	};
123	
124	type SelectedCapacityProps = {
125	  state: WizardState['createLocalVolumeSet'];
126	  dispatch: WizardDispatch;
127	  chartDisks: DiscoveredDisk[];
128	  allDiscoveredDisks: DiscoveredDisk[];
129	};
130	
131	const filterNodes = (nodesData: NodeData[], filteredNodes: Set<string>) => {
132	  const filteredData = nodesData?.filter((node: NodeData) =>
133	    filteredNodes.has(getName(node))
134	  );
135	  return createWizardNodeState(filteredData);
136	};
137	
138	const NodeListModal: React.FC<NodeListModalProps> = ({
139	  filteredNodes,
140	  onCancel,
141	  showNodeList,
142	}) => {
143	  const { t } = useCustomTranslation();
144	
145	  const [nodesData, nodesLoaded, nodesLoadError] = useNodesData();
146	  const filteredData = React.useMemo(
147	    () => filterNodes(nodesData, filteredNodes),
148	    [nodesData, filteredNodes]
149	  );
150	
151	  return (
152	    <Modal
153	      title={t('Selected nodes')}
154	      isOpen={showNodeList}
155	      onClose={onCancel}
156	      className="odf-install__filtered-modal"
157	      actions={[
158	        <Button key="confirm" variant="primary" onClick={onCancel}>
159	          {t('Close')}
160	        </Button>,
161	      ]}
162	    >
163	      <StatusBox
164	        skeleton={<div className="loading-skeleton--table" />}
165	        data={nodesData}
166	        loaded={nodesLoaded}
167	        loadError={nodesLoadError}
168	      >
169	        <SelectedNodesTable data={filteredData} showDetails={false} />
170	      </StatusBox>
171	    </Modal>
172	  );
173	};
174	
175	type NodeListModalProps = {
176	  showNodeList: boolean;
177	  filteredNodes: Set<string>;
178	  onCancel: () => void;
179	};

